const OpacityView  = ({ viewId, activeView, children }) => {
	return(
		<div className={"opacityView"} style={{opacity : viewId=== activeView?1:0, marginTop: 29 }}>
			{viewId=== activeView?children:null}
		</div>
	)

}




	
const convert2A =  (v)=>{
	let nob = {}
	if(Array.isArray(v)){
		v.map(it=>{
			nob[gen16CodeId()] = it;
		})
	}
	else{
		return v;
	}
	return nob;
}
